const inputItems = $input.all();

const reservations = inputItems.flatMap(item => {
  if (Array.isArray(item.json)) {
    return item.json;
  }

  if (Array.isArray(item.json.data)) {
    return item.json.data;
  }

  return [item.json];
});

return reservations.map(r => ({
  json: {
    _id: r._id,
    id: r.id,
    checkInDate: r.checkInDate,
    checkOutDate: r.checkOutDate,
    _idlisting: r._idlisting,
    guests: r.guests,
    guestsDetails: r.guestsDetails,
    type: r.type,
    reservationUrl: r.reservationUrl
  }
}));

const HARDCODED_NUMBERS = {"698ead2e065bcaac0d2f4940":"901","698b996c4472180c6843bfce":"902","698f5783609280f0178b152e":"709","698eb2ef8563bcd9abfb83f3":"702"};
// Build HTML report with guest names, phones, WhatsApp links, and conserjeria button
// Uses reservation detail data with names/phones from detail API
// Uses meta from GetFechasYAlojamientos node

const allItems = $input.all().map(i => i.json);

// Si los alojamientos vienen en el primer item de entrada, deja esta línea:
const meta = $input.first().json;

// Si los alojamientos vienen desde otro nodo, usa esta línea en vez de la anterior:
// const meta = $('GetFechasYAlojamientos').first().json;

const alojArr = Array.isArray(meta.alojamientos) ? meta.alojamientos : [];

const listingMap = {};
for (const a of alojArr) {
  if (a.listing_id) {
    listingMap[a.listing_id] = a.listing_name || a.listing_id;
  }
}

// Helpers
const todayCLT = new Date(
  new Date().toLocaleString("en-US", { timeZone: "America/Santiago" })
);

const tomorrowCLT = new Date(todayCLT);
tomorrowCLT.setDate(tomorrowCLT.getDate() + 1);

const fmtDate = d => d.toISOString().split("T")[0];

const todayKey = fmtDate(todayCLT);
const tomorrowKey = fmtDate(tomorrowCLT);

const in3Days = new Date(todayCLT.getTime() + 3 * 86400000);
const in3DaysKey = fmtDate(in3Days);

const normalize = v =>
  v === null || v === undefined ? null : String(v).slice(0, 10);

const ddmmyyyy = ymd =>
  ymd ? ymd.split("-").reverse().join("-") : "";

const toTitle = s =>
  String(s || "").replace(
    /\p{L}[\p{L}\p{Mn}]*/gu,
    w => w[0].toUpperCase() + w.slice(1)
  );

const esc = s =>
  String(s ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

const fmtDia = new Intl.DateTimeFormat("es-CL", {
  weekday: "long",
  day: "numeric",
  month: "long",
  timeZone: "America/Santiago"
});

const diaTexto = ymd =>
  ymd
    ? toTitle(
        fmtDia
          .format(new Date(ymd + "T12:00:00-03:00"))
          .replace(",", "")
      )
    : "";

const getGuestName = r => {
  const list = r.guestsDetails?.list || [];
  const primary = list.find(g => g.primary) || list[0];
  return primary?.name || "";
};

const getPhone = r => {
  const list = r.guestsDetails?.list || [];
  const primary = list.find(g => g.primary) || list[0];
  const phones = primary?.phones || [];
  return phones[0]?.iso || "";
};

const waLink = (phone, text) => {
  if (!phone) return "";

  const clean = String(phone).replace(/[^0-9]/g, "");

  return clean
    ? "https://wa.me/" + clean + "?text=" + encodeURIComponent(text || "Hola")
    : "";
};

const reservas = allItems;

// Conserjeria message: check-ins next 3 days
const conserjeNum = "56923976934";

// Sort by checkInDate and group by date
const reservasSorted = [...reservas].sort((a, b) => {
  const ca = normalize(a.checkInDate) || "";
  const cb = normalize(b.checkInDate) || "";
  return ca.localeCompare(cb);
});

const conserjeByDate = new Map();
for (const r of reservasSorted) {
  const cin = normalize(r.checkInDate);
  if (!cin || cin < todayKey || cin > in3DaysKey) continue;
  if (!conserjeByDate.has(cin)) conserjeByDate.set(cin, []);
  conserjeByDate.get(cin).push(r);
}

const conserjeLines = [];
for (const [cin, items] of conserjeByDate) {
  conserjeLines.push("📅 " + diaTexto(cin) + " (" + ddmmyyyy(cin) + ")");

  for (const r of items) {
    const depto = HARDCODED_NUMBERS[r._idlisting] || listingMap[r._idlisting] || r._idlisting || "?";
    const guest = getGuestName(r);
    const cout = normalize(r.checkOutDate) || "";

    conserjeLines.push("Depto " + depto + " --");
    conserjeLines.push((guest || "sin nombre") + " · Chile · ");
    conserjeLines.push((r.guests || 1) + " pers · checkout " + ddmmyyyy(cout));
    conserjeLines.push("");
  }
}

const conserjeMsg =
  conserjeLines.length > 0
    ? "Hola Don David, informo check in:\n\n" + conserjeLines.join("\n")
    : "Hola Don David, sin check-ins los proximos 3 dias";

const conserjeUrl = waLink(conserjeNum, conserjeMsg);

// Build sections
const checkinsHoy = reservas.filter(
  r => normalize(r.checkInDate) === todayKey
);

const checkoutsHoy = reservas.filter(
  r => normalize(r.checkOutDate) === todayKey
);

const checkoutsManana = reservas.filter(
  r => normalize(r.checkOutDate) === tomorrowKey
);

let body = "";

// CONSERJERIA BUTTON
body += `
  <div style="text-align:center;padding:16px;background:#1a2a3a;border-radius:12px;margin-bottom:16px">
    <a href="${esc(conserjeUrl)}" target="_blank" style="background:#25D366;color:white;padding:14px 28px;border-radius:8px;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block">
      📋 Informar huéspedes a conserjería
    </a>
    <div style="color:#8899aa;margin-top:8px;font-size:12px">
      Check-ins próximos 3 días
    </div>
  </div>
`;

// CHECK-IN TODAY
if (checkinsHoy.length > 0) {
  body += `
    <section style="background:#0d2818;border:1px solid #22c55e;border-radius:12px;padding:16px;margin-bottom:16px">
      <div style="font-size:18px;font-weight:bold;color:#22c55e;margin-bottom:12px">
        🟢 CHECK-IN HOY · ${esc(diaTexto(todayKey))}
      </div>
  `;

  for (const r of checkinsHoy) {
    const depto = HARDCODED_NUMBERS[r._idlisting] || listingMap[r._idlisting] || r._idlisting || "?";
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cout = normalize(r.checkOutDate);
    const link = waLink(phone, "Hola");

    body += `
      <div style="padding:8px;margin:4px 0;background:#0a1f12;border-radius:8px">
        <strong>Depto ${esc(depto)}</strong> · ${esc(toTitle(guest))} · ${esc(r.guests || 1)} pers · hasta ${esc(ddmmyyyy(cout))}
        ${
          phone
            ? `<a href="${esc(link)}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>`
            : ""
        }
      </div>
    `;
  }

  body += `</section>`;
}

// CHECK-OUT TODAY: ASEO
if (checkoutsHoy.length > 0) {
  body += `
    <section style="background:#2a1010;border:1px solid #ef4444;border-radius:12px;padding:16px;margin-bottom:16px">
      <div style="font-size:18px;font-weight:bold;color:#ef4444;margin-bottom:12px">
        🔴 ASEO HOY · ${esc(diaTexto(todayKey))}
      </div>
  `;

  for (const r of checkoutsHoy) {
    const depto = HARDCODED_NUMBERS[r._idlisting] || listingMap[r._idlisting] || r._idlisting || "?";
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cin = normalize(r.checkInDate);
    const link = waLink(phone, "Hola");

    body += `
      <div style="padding:8px;margin:4px 0;background:#1a0a0a;border-radius:8px">
        <strong>Depto ${esc(depto)}</strong> · ${esc(toTitle(guest))} · desde ${esc(ddmmyyyy(cin))}
        ${
          phone
            ? `<a href="${esc(link)}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>`
            : ""
        }
      </div>
    `;
  }

  body += `</section>`;
}

// ASEO MAÑANA
if (checkoutsManana.length > 0) {
  body += `
    <section style="background:#332211;border:2px solid #f59e0b;border-radius:12px;padding:16px;margin-bottom:16px">
      <div style="font-size:18px;font-weight:bold;color:#f59e0b;margin-bottom:12px">
        🟠 ASEO MAÑANA · ${esc(diaTexto(tomorrowKey))} ⚠️
      </div>
  `;

  for (const r of checkoutsManana) {
    const depto = HARDCODED_NUMBERS[r._idlisting] || listingMap[r._idlisting] || r._idlisting || "?";
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cin = normalize(r.checkInDate);
    const link = waLink(phone, "Hola");

    body += `
      <div style="padding:8px;margin:4px 0;background:#2a1a08;border-radius:8px">
        <strong>Depto ${esc(depto)}</strong> · ${esc(toTitle(guest))} · desde ${esc(ddmmyyyy(cin))}
        ${
          phone
            ? `<a href="${esc(link)}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>`
            : ""
        }
      </div>
    `;
  }

  body += `</section>`;
}

// PROXIMOS DIAS
const remaining = reservas.filter(r => {
  const cout = normalize(r.checkOutDate);
  return cout && cout !== todayKey && cout !== tomorrowKey;
});

if (remaining.length > 0) {
  const byDate = new Map();

  for (const r of remaining) {
    const cout = normalize(r.checkOutDate);
    if (!cout) continue;

    if (!byDate.has(cout)) {
      byDate.set(cout, []);
    }

    byDate.get(cout).push(r);
  }

  body += `
    <section style="background:#0f1626;border:1px solid #223055;border-radius:12px;padding:16px">
      <div style="font-size:18px;font-weight:bold;color:#a9b6d6;margin-bottom:12px">
        🔵 PRÓXIMOS DÍAS
      </div>
  `;

  for (const [dia, items] of [...byDate].sort()) {
    body += `
      <div style="font-size:16px;font-weight:bold;color:#64748B;margin:8px 0">
        ${esc(ddmmyyyy(dia))} · ${esc(diaTexto(dia))}
      </div>
    `;

    for (const r of items) {
      const depto = HARDCODED_NUMBERS[r._idlisting] || listingMap[r._idlisting] || r._idlisting || "?";
      const guest = getGuestName(r);
      const phone = getPhone(r);
      const cin = normalize(r.checkInDate);
      const link = waLink(phone, "Hola");

      body += `
        <div style="padding:6px;margin:2px 0;border-bottom:1px solid #1a2744">
          <strong>Depto ${esc(depto)}</strong> · ${esc(toTitle(guest))} · desde ${esc(ddmmyyyy(cin))}
          ${
            phone
              ? `<a href="${esc(link)}" target="_blank" style="color:#25D366;font-size:12px">📞</a>`
              : ""
          }
        </div>
      `;
    }
  }

  body += `</section>`;
}

const html = `
<!doctype html>
<html lang="es">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>Aseos v3 · SandiegoApart</title>
  <style>
    :root {
      --bg: #0b0f19;
      --text: #e8eefc;
    }

    body {
      margin: 0;
      font-family: system-ui, sans-serif;
      background: var(--bg);
      color: var(--text);
      padding: 16px;
    }

    a {
      color: #25D366;
    }
  </style>
</head>
<body>
  <h1>🧹 Aseos · SandiegoApart</h1>

  ${body}

  <div style="text-align:center;padding:16px;color:#8899aa;font-size:12px;margin-top:24px">
    Actualizado: ${esc(new Date().toLocaleString("es-CL", { timeZone: "America/Santiago" }))} · Fuente: API Stays.net
  </div>
</body>
</html>
`;

return [
  {
    json: {
      html
    }
  }
];
